{\LARGE \bfseries Bezpečnost při práci s elektřinou} \\[2mm]
{\color{zfblue}\hrule height 1.5pt}
\vspace{4mm}

\begin{tcolorbox}[colback=zfred!10, colframe=zfred!70, boxrule=0.7pt, arc=2pt, left=6pt, right=6pt, top=4pt, bottom=4pt]
\textbf{Elektřina je užitečná, ale nebezpečná!} Při napětí $\geq$ 50 V hrozí \textbf{úraz elektrickým proudem}, který může zabít. V zásuvkách je 230 V.
\end{tcolorbox}

\vspace{4mm}
{\Large \bfseries \color{zfblue} Co dělá elektrický proud s tělem}
\vspace{2mm}

\begin{itemize}
    \item Křečovité stažení svalů -- člověk nemůže pustit drát.
    \item Popáleniny v místě, kudy proud vstoupil a vystoupil.
    \item Zástava srdce a dýchání.
    \item Smrtelné nebezpečí -- závisí na velikosti proudu, době a cestě tělem.
\end{itemize}

\vspace{4mm}
{\Large \bfseries \color{zfblue} Bezpečnostní pravidla}
\vspace{2mm}

\begin{center}
\renewcommand{\arraystretch}{1.4}
\setlength{\tabcolsep}{8pt}
\begin{tabular}{|>{\centering\arraybackslash}p{0.8cm}|p{12cm}|}
\hline
\rowcolor{zfgreen!25}
\bfseries ✓ & \bfseries Co dělat \\
\hline
✓ & Pracuj jen s nízkonapěťovými zdroji (baterie do 12 V). \\
✓ & Před opravou vždy \textbf{vypni jistič} v rozvodné skříni. \\
✓ & Měj \textbf{suché ruce} -- voda vede proud. \\
✓ & Používej \textbf{nepoškozené} kabely a zástrčky. \\
✓ & Při bouřce nestoj pod stromem ani v otevřeném terénu. \\
\hline
\end{tabular}

\vspace{2mm}
\renewcommand{\arraystretch}{1.4}
\setlength{\tabcolsep}{8pt}
\begin{tabular}{|>{\centering\arraybackslash}p{0.8cm}|p{12cm}|}
\hline
\rowcolor{zfred!25}
\bfseries ✗ & \bfseries Co nikdy nedělat \\
\hline
✗ & \textbf{Nikdy} nestrkej do zásuvky předměty (tužku, drát, prsty). \\
✗ & Nesahej na elektrické zařízení \textbf{mokrýma rukama}. \\
✗ & Nepoužívej spotřebič s \textbf{poškozeným kabelem}. \\
✗ & Nelez na sloupy s vysokým napětím (značka \textbf{trojúhelník s bleskem}). \\
✗ & Neodstraňuj kryty zásuvek a vypínačů sám. \\
\hline
\end{tabular}
\end{center}

